final:
module RefModule (
    input wire [3:0] data_in,
    input wire [1:0] sel,
    output wire data_out
);

    wire __data_out_tmp = (sel == 2'b00) ? data_in[0] :
                      (sel == 2'b01) ? data_in[1] :
                      (sel == 2'b10) ? data_in[2] :
                                       data_in[3];
    assign data_out = __data_out_tmp;

endmodule
